import novamind_api as nm, math
D=nm.vars.current_day
prices={'A':149,'B':239,'C':549}
group={'S2':60,'S3':80,'D_S04':100,'D_S07':100,'D_S10':90,'S1':125,'D_S03':125,'D_S05':50,'D_S06':120,'D_S01':100,'D_S02':100,'D_S08':110,'D_S09':100}
gp={'S2':{'A':20},'S3':{'A':20},'D_S04':{'B':80},'D_S07':{'B':20},'D_S10':{'B':60},'D_S06':{'B':90},'D_S01':{'B':80},'D_S02':{'B':80},'D_S08':{'B':80},'D_S09':{'B':80}}
def eff(g,p): return max(0,prices[p]-group.get(g,0)-gp.get(g,{}).get(p,0))
rows=nm.query("""SELECT c.group_id,s.plan,s.billing_day_mod30 mod,COUNT(*) n FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.status='subscribed' AND c.customer_type='small' GROUP BY c.group_id,s.plan,s.billing_day_mod30""")['rows']
# Base churn: observed post-bridge/transition; A cohorts intentionally high, B improving after current price + support/R&D.
churn={('S2','B'):0.23,('S3','B'):0.34,('D_S07','B'):0.11,('D_S10','B'):0.06,
       ('S2','A'):0.65,('S3','A'):0.75,('D_S07','A'):0.72,('D_S10','A'):0.60,
       ('S3','C'):0.10,('D_S02','B'):0.75,('D_S09','B'):0.65,('D_S04','B'):0.85,
       ('D_S02','A'):0.8,('D_S04','A'):0.8,('D_S09','A'):0.8}
def ch(g,p): return churn.get((g,p),0.9)
for w in range(1,5):
    mods=[(D+7*(w-1)+i)%30 for i in range(1,8)]
    gross=0; due=0; full=0
    for r in rows:
        if r['mod'] in mods:
            p=eff(r['group_id'],r['plan']); full += r['n']*p; gross += r['n']*(1-ch(r['group_id'],r['plan']))*p; due+=r['n']
    newpay=700000 if w==1 else 650000 if w==2 else 600000 if w==3 else 600000
    print(w,mods,'due_n',due,'full_current',round(full),'renew_after_churn',round(gross),'newpay',newpay,'gross_total',round(gross+newpay))

